--
-- Table structure for table `departments`
--

DROP TABLE IF EXISTS `departments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `departments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `dept_code` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ລະຫັດພາກ/ສ່ວນ ເຊັ່ນ 01, 02',
  `department_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `department_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `budget_amount` decimal(18,2) NOT NULL DEFAULT '0.00' COMMENT 'ງົບປະມານຂອງພາກ/ສ່ວນ',
  `initial_budget` decimal(15,2) NOT NULL DEFAULT '0.00',
  PRIMARY KEY (`id`),
  UNIQUE KEY `department_name` (`department_name`)
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

