DROP TABLE IF EXISTS `expense_catalog_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `expense_catalog_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `subsection_id` bigint unsigned NOT NULL,
  `item_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `chart_of_account_id` int unsigned DEFAULT NULL,
  `pattern_id` bigint unsigned DEFAULT NULL,
  `default_values` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin,
  `sort_order` smallint unsigned NOT NULL DEFAULT '1',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `expense_catalog_items_chart_of_account_id_foreign` (`chart_of_account_id`),
  KEY `expense_catalog_items_pattern_id_foreign` (`pattern_id`),
  KEY `expense_catalog_items_subsection_id_sort_order_index` (`subsection_id`,`sort_order`),
  CONSTRAINT `expense_catalog_items_chart_of_account_id_foreign` FOREIGN KEY (`chart_of_account_id`) REFERENCES `chart_of_accounts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_catalog_items_pattern_id_foreign` FOREIGN KEY (`pattern_id`) REFERENCES `expense_patterns` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_catalog_items_subsection_id_foreign` FOREIGN KEY (`subsection_id`) REFERENCES `expense_subsections` (`id`) ON DELETE CASCADE,
  CONSTRAINT `expense_catalog_items_chk_1` CHECK (json_valid(`default_values`))
) ENGINE=InnoDB AUTO_INCREMENT=6874 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

