DROP TABLE IF EXISTS `expense_plan_rows`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `expense_plan_rows` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `expense_plan_id` bigint unsigned NOT NULL,
  `planning_year_id` bigint unsigned NOT NULL,
  `section_id` bigint unsigned NOT NULL,
  `subsection_id` bigint unsigned DEFAULT NULL,
  `catalog_item_id` bigint unsigned DEFAULT NULL,
  `chart_of_account_id` int unsigned DEFAULT NULL,
  `pattern_id` bigint unsigned DEFAULT NULL,
  `version` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plan_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `item_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plan_detail` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `detail` text COLLATE utf8mb4_unicode_ci,
  `calculation_values` json DEFAULT NULL,
  `pattern_snapshot` json DEFAULT NULL,
  `created_by` int unsigned DEFAULT NULL,
  `updated_by` int unsigned DEFAULT NULL,
  `source_expense_plan_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `expense_rows_source_plan_unique` (`source_expense_plan_id`),
  KEY `expense_plan_rows_expense_plan_id_foreign` (`expense_plan_id`),
  KEY `expense_plan_rows_section_id_foreign` (`section_id`),
  KEY `expense_plan_rows_subsection_id_foreign` (`subsection_id`),
  KEY `expense_plan_rows_chart_of_account_id_foreign` (`chart_of_account_id`),
  KEY `expense_plan_rows_pattern_id_foreign` (`pattern_id`),
  KEY `expense_rows_year_section_idx` (`planning_year_id`,`section_id`,`subsection_id`),
  KEY `expense_rows_catalog_item_idx` (`catalog_item_id`),
  CONSTRAINT `expense_plan_rows_catalog_item_id_foreign` FOREIGN KEY (`catalog_item_id`) REFERENCES `expense_catalog_items` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plan_rows_chart_of_account_id_foreign` FOREIGN KEY (`chart_of_account_id`) REFERENCES `chart_of_accounts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plan_rows_expense_plan_id_foreign` FOREIGN KEY (`expense_plan_id`) REFERENCES `expense_plans` (`id`) ON DELETE CASCADE,
  CONSTRAINT `expense_plan_rows_pattern_id_foreign` FOREIGN KEY (`pattern_id`) REFERENCES `expense_patterns` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plan_rows_planning_year_id_foreign` FOREIGN KEY (`planning_year_id`) REFERENCES `planning_years` (`id`) ON DELETE CASCADE,
  CONSTRAINT `expense_plan_rows_section_id_foreign` FOREIGN KEY (`section_id`) REFERENCES `expense_sections` (`id`) ON DELETE CASCADE,
  CONSTRAINT `expense_plan_rows_subsection_id_foreign` FOREIGN KEY (`subsection_id`) REFERENCES `expense_subsections` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=394 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

